SELECT DATE_FORMAT(h.create_time, '%Y-%m-%d') AS date, COUNT(*) AS count FROM biz_study_history h WHERE h.create_time >= #{startDate}
AND h.user_id = #{userId}
GROUP BY DATE_FORMAT(h.create_time, '%Y-%m-%d') ORDER BY date ASC

SELECT *
FROM biz_study_history
WHERE user_id = #{userId}
  AND create_time  >=  #{startTime}
  AND create_time  <=  #{endTime}
ORDER BY create_time ASC
